    function normalizeHotkeyAppBinding(entry) {
      if (!entry || typeof entry !== "object") return null;
      const hotkeyId = String(entry.hotkeyId || entry.automationId || "").trim();
      const processName = String(entry.processName || entry.gameMatchText || "").trim();
      if (!hotkeyId || !processName) return null;
      return {
        hotkeyId,
        appName: String(entry.appName || entry.gameAppName || "").trim(),
        appLaunch: String(entry.appLaunch || entry.gameAppLaunch || "").trim(),
        processName,
        createdAt: Number(entry.createdAt) || Date.now()
      };
    }

    function migrateLegacyProfileAppBindings() {
      return (Array.isArray(profileAutomations) ? profileAutomations : [])
        .map((item) => {
          const rawId = String(item?.id || "").trim();
          const processName = String(item?.gameMatchText || "").trim();
          if (!rawId || item?.gameBindingEnabled !== true || !processName) return null;
          return normalizeHotkeyAppBinding({
            hotkeyId: `profile:${rawId}`,
            appName: item?.gameAppName,
            appLaunch: item?.gameAppLaunch,
            processName,
            createdAt: item?.createdAt
          });
        })
        .filter(Boolean);
    }

    function loadHotkeyAppBindings() {
      try {
        const raw = localStorage.getItem(HOTKEY_APP_BINDINGS_STORAGE_KEY);
        if (raw) {
          const parsed = JSON.parse(raw);
          if (Array.isArray(parsed)) {
            return parsed
              .map((entry) => normalizeHotkeyAppBinding(entry))
              .filter(Boolean);
          }
        }
      } catch {
        // Ignore malformed storage; fall through to migration.
      }

      const migrated = migrateLegacyProfileAppBindings();
      if (migrated.length) {
        try {
          localStorage.setItem(HOTKEY_APP_BINDINGS_STORAGE_KEY, JSON.stringify(migrated));
        } catch {
          // Ignore storage errors
        }
      }
      return migrated;
    }

    function saveHotkeyAppBindings() {
      hotkeyAppBindings = (Array.isArray(hotkeyAppBindings) ? hotkeyAppBindings : [])
        .map((entry) => normalizeHotkeyAppBinding(entry))
        .filter(Boolean);
      try {
        localStorage.setItem(HOTKEY_APP_BINDINGS_STORAGE_KEY, JSON.stringify(hotkeyAppBindings));
      } catch {
        // Ignore storage errors
      }
      publishAutomationHotkeys();
    }

    function normalizeAppsFilesAutomation(entry) {
      if (!entry || typeof entry !== "object") return null;
      const normalizedSteps = [];
      if (Array.isArray(entry.steps)) {
        entry.steps.forEach((step) => {
          if (!step || typeof step !== "object") return;
          const kind = APPS_FILES_KINDS.includes(step.kind) ? step.kind : "app";
          const target = kind === "delay"
            ? normalizeDelayMs(step.target)
            : String(step.target || "").trim();
          if (!target) return;
          normalizedSteps.push({
            id: String(step.id || uid()),
            kind,
            target,
            appName: String(step?.appName || "")
          });
        });
      }
      // Legacy support: old single-target entries
      if (!normalizedSteps.length) {
        const legacyTarget = String(entry.target || "").trim();
        if (legacyTarget) {
          normalizedSteps.push({
            id: uid(),
            kind: APPS_FILES_KINDS.includes(entry.kind) ? entry.kind : "app",
            target: legacyTarget,
            appName: String(entry?.appName || "")
          });
        }
      }
      if (!normalizedSteps.length) return null;
      const firstStep = normalizedSteps[0];
      const name = String(entry.name || "").trim() || deriveNameFromTarget(firstStep.target, firstStep.kind);
      const createdAt = Number(entry.createdAt) || Date.now();
      return {
        id: String(entry.id || uid()),
        name,
        hotkey: String(entry.hotkey || "").trim(),
        enabled: entry.enabled !== false,
        steps: normalizedSteps,
        createdAt
      };
    }

    function normalizeKeyboardAutomation(entry) {
      if (!entry || typeof entry !== "object") return null;
      const normalizedSteps = (Array.isArray(entry.steps) ? entry.steps : [])
        .map((step) => {
          if (!step || typeof step !== "object") return null;
          const kind = KEYBOARD_STEP_KINDS.includes(step.kind) ? step.kind : "key";
          const value = kind === "delay"
            ? normalizeDelayMs(step.value)
            : String(step.value || "").trim();
          if (!value) return null;
          return {
            id: String(step.id || uid()),
            kind,
            value
          };
        })
        .filter(Boolean);
      if (!normalizedSteps.length) return null;
      const firstStep = normalizedSteps[0];
      return {
        id: String(entry.id || uid()),
        name: String(entry.name || "").trim() || deriveKeyboardName(firstStep),
        hotkey: String(entry.hotkey || "").trim(),
        triggerMode: ["once", "hold", "toggle"].includes(String(entry.triggerMode || "").trim()) ? String(entry.triggerMode).trim() : "once",
        enabled: entry.enabled !== false,
        steps: normalizedSteps,
        createdAt: Number(entry.createdAt) || Date.now()
      };
    }

    function normalizeMouseAutomation(entry) {
      if (!entry || typeof entry !== "object") return null;
      const normalizedSteps = (Array.isArray(entry.steps) ? entry.steps : [])
        .map((step) => {
          if (!step || typeof step !== "object") return null;
          const kind = MOUSE_STEP_KINDS.includes(step.kind) ? step.kind : "click";
          let value = String(step.value || "").trim();
          if (kind === "delay") value = normalizeDelayMs(value);
          if (!value) return null;
          if (["click", "down", "up"].includes(kind)) {
            value = MOUSE_BUTTON_VALUES.includes(value.toLowerCase()) ? value.toLowerCase() : "left";
          }
          return {
            id: String(step.id || uid()),
            kind,
            value
          };
        })
        .filter(Boolean);
      if (!normalizedSteps.length) return null;
      const firstStep = normalizedSteps[0];
      return {
        id: String(entry.id || uid()),
        name: String(entry.name || "").trim() || deriveMouseName(firstStep, getLang() === "de"),
        hotkey: String(entry.hotkey || "").trim(),
        triggerMode: ["once", "hold", "toggle"].includes(String(entry.triggerMode || "").trim()) ? String(entry.triggerMode).trim() : "once",
        enabled: entry.enabled !== false,
        steps: normalizedSteps,
        createdAt: Number(entry.createdAt) || Date.now()
      };
    }

    function normalizeSystemAutomation(entry) {
      if (!entry || typeof entry !== "object") return null;
      const normalizedSteps = (Array.isArray(entry.steps) ? entry.steps : [])
        .map((step) => {
          if (!step || typeof step !== "object") return null;
          let kind = SYSTEM_STEP_KINDS.includes(step.kind) ? step.kind : "volume";
          let value = String(step.value || "").trim();
          let amount = Math.max(1, Math.round(Number(step.amount) || 1));
          if (!SYSTEM_STEP_KINDS.includes(step.kind)) {
            if (value.startsWith("volume_")) kind = "volume";
            else if (value.startsWith("media_")) kind = "media";
            else if (value.startsWith("screenshot_") || value === "screenshot" || value.startsWith("lock")) kind = "action";
          }
          if (kind === "delay") value = normalizeDelayMs(value);
          if (!value) return null;
          if (kind === "action" && (value === "screenshot" || value === "screenshot_video")) value = "screenshot_image";
          if (kind === "action" && value === "lock") value = "lock_screen";
          if (kind !== "delay") {
            const options = Array.isArray(SYSTEM_ACTION_VALUES[kind]) ? SYSTEM_ACTION_VALUES[kind] : [];
            if (!options.includes(value)) return null;
          }
          if (kind !== "volume" || !["volume_up", "volume_down"].includes(value)) amount = 1;
          return {
            id: String(step.id || uid()),
            kind,
            value,
            amount
          };
        })
        .filter(Boolean);
      if (!normalizedSteps.length) return null;
      const firstStep = normalizedSteps[0];
      return {
        id: String(entry.id || uid()),
        name: String(entry.name || "").trim() || deriveSystemName(firstStep, getLang() === "de"),
        hotkey: String(entry.hotkey || "").trim(),
        triggerMode: ["once", "hold", "toggle"].includes(String(entry.triggerMode || "").trim()) ? String(entry.triggerMode).trim() : "once",
        enabled: entry.enabled !== false,
        steps: normalizedSteps,
        createdAt: Number(entry.createdAt) || Date.now()
      };
    }

    function normalizeProfileAutomation(entry) {
      if (!entry || typeof entry !== "object") return null;
      const normalizedSteps = (Array.isArray(entry.steps) ? entry.steps : [])
        .map((step) => {
          if (!step || typeof step !== "object") return null;
          const kind = PROFILE_STEP_KINDS.includes(step.kind) ? step.kind : "apps-files";
          let refId = String(step.refId || "");
          let value = String(step.value || "");
          if (kind === "delay") {
            value = normalizeDelayMs(value);
            refId = "";
            if (!value) return null;
          } else {
            value = "";
            if (!refId) return null;
          }
          return {
            id: String(step.id || uid()),
            kind,
            refId,
            value
          };
        })
        .filter(Boolean);
      if (!normalizedSteps.length) return null;
      const gameMatchText = String(entry.gameMatchText || "").trim();
      const gameBindingEnabled = entry.gameBindingEnabled === true && Boolean(gameMatchText);
      return {
        id: String(entry.id || uid()),
        name: String(entry.name || "").trim() || deriveProfileName(normalizedSteps[0], getLang() === "de"),
        hotkey: String(entry.hotkey || "").trim(),
        triggerMode: ["once", "hold", "toggle"].includes(String(entry.triggerMode || "").trim()) ? String(entry.triggerMode).trim() : "once",
        gameBindingEnabled,
        gameAppName: String(entry.gameAppName || "").trim(),
        gameAppLaunch: String(entry.gameAppLaunch || "").trim(),
        gameMatchText,
        enabled: gameBindingEnabled ? true : entry.enabled !== false,
        steps: normalizedSteps,
        createdAt: Number(entry.createdAt) || Date.now()
      };
    }

    function getAutomationBindingKey(sourceType, rawId) {
      const normalizedType = String(sourceType || "").trim();
      const normalizedId = String(rawId || "").trim();
      if (!normalizedType || !normalizedId) return "";
      return `${normalizedType}:${normalizedId}`;
    }

    function getHotkeyAppBindingById(hotkeyId) {
      const normalizedId = String(hotkeyId || "").trim();
      if (!normalizedId) return null;
      return (Array.isArray(hotkeyAppBindings) ? hotkeyAppBindings : []).find((entry) => String(entry?.hotkeyId || "").trim() === normalizedId) || null;
    }

    function getHotkeyAppBindingForItem(sourceType, item) {
      return getHotkeyAppBindingById(getAutomationBindingKey(sourceType, item?.id));
    }

    function isAutomationAppBound(sourceType, item) {
      return Boolean(String(getHotkeyAppBindingForItem(sourceType, item)?.processName || "").trim());
    }

    function getAutomationBoundAppLabel(sourceType, item) {
      const binding = getHotkeyAppBindingForItem(sourceType, item);
      if (!binding) return "";
      return String(binding.appName || binding.processName || "").trim();
    }

    function getAutomationEffectiveEnabled(sourceType, item) {
      if (isAutomationAppBound(sourceType, item)) return true;
      return item?.enabled !== false;
    }

    function getAutomationStatusMeta(sourceType, item, isDe) {
      if (isAutomationAppBound(sourceType, item)) {
        return {
          className: "is-auto",
          label: isDe ? "Per App" : "Per app"
        };
      }
      return item?.enabled === false
        ? { className: "is-disabled", label: isDe ? "Deaktiviert" : "Disabled" }
        : { className: "is-enabled", label: isDe ? "Aktiviert" : "Enabled" };
    }

    function getAutomationBindingMetaLabel(sourceType, item, isDe) {
      const label = getAutomationBoundAppLabel(sourceType, item);
      if (!label) return "";
      return isDe ? `App: ${label}` : `App: ${label}`;
    }

    function isAutomationRuntimeAllowed(sourceType, item) {
      if (!isAutomationAppBound(sourceType, item)) {
        return item?.enabled !== false;
      }
      const binding = getHotkeyAppBindingForItem(sourceType, item);
      const matchText = String(binding?.processName || "").trim();
      if (!matchText) {
        return false;
      }
      const checker = window.__KC_IS_PROCESS_MATCH_ACTIVE;
      if (typeof checker !== "function") {
        return true;
      }
      return checker(matchText);
    }

    function getAutomationSourceLabel(sourceType, isDe) {
      if (sourceType === "keyboard") return isDe ? "Tastatur-Eingabe" : "Keyboard Input";
      if (sourceType === "mouse") return isDe ? "Maus-Eingabe" : "Mouse Input";
      if (sourceType === "system") return "System";
      if (sourceType === "profile") return isDe ? "Kombination" : "Combination";
      return isDe ? "Apps & Dateien" : "Apps & Files";
    }

    function getAutomationSourceCode(sourceType) {
      if (sourceType === "keyboard") return "KEY";
      if (sourceType === "mouse") return "MOUSE";
      if (sourceType === "system") return "SYS";
      if (sourceType === "profile") return "FLOW";
      return "APP";
    }

    function buildAllHotkeyEntries() {
      function buildEntries(items, sourceType) {
        return (Array.isArray(items) ? items : [])
          .map((item) => {
            const rawId = String(item?.id || "").trim();
            const shortcut = String(item?.hotkey || "").trim();
            if (!rawId || !shortcut) return null;
            const id = getAutomationBindingKey(sourceType, rawId);
            const binding = getHotkeyAppBindingById(id);
            return {
              id,
              rawId,
              sourceType,
              name: String(item?.name || "").trim() || id,
              hotkey: shortcut,
              triggerMode: String(item?.triggerMode || "").trim(),
              stepCount: Array.isArray(item?.steps) ? item.steps.length : 0,
              enabled: item?.enabled !== false,
              effectiveEnabled: getAutomationEffectiveEnabled(sourceType, item),
              boundAppLabel: String(binding?.appName || binding?.processName || "").trim(),
              boundProcessName: String(binding?.processName || "").trim(),
              boundAppLaunch: String(binding?.appLaunch || "").trim(),
              createdAt: Number(item?.createdAt) || Date.now()
            };
          })
          .filter(Boolean);
      }

      return [
        ...buildEntries(appsFilesAutomations, "apps-files"),
        ...buildEntries(keyboardAutomations, "keyboard"),
        ...buildEntries(mouseAutomations, "mouse"),
        ...buildEntries(systemAutomations, "system"),
        ...buildEntries(profileAutomations, "profile")
      ];
    }

    function upsertHotkeyAppBinding(hotkeyId, app) {
      const normalizedId = String(hotkeyId || "").trim();
      const normalized = normalizeHotkeyAppBinding({
        hotkeyId: normalizedId,
        appName: app?.name,
        appLaunch: app?.launch,
        processName: app?.processName
      });
      if (!normalized) return false;
      hotkeyAppBindings = (Array.isArray(hotkeyAppBindings) ? hotkeyAppBindings : [])
        .filter((entry) => String(entry?.hotkeyId || "").trim() !== normalizedId);
      hotkeyAppBindings.unshift(normalized);
      saveHotkeyAppBindings();
      return true;
    }

    function removeHotkeyAppBinding(hotkeyId) {
      const normalizedId = String(hotkeyId || "").trim();
      const before = Array.isArray(hotkeyAppBindings) ? hotkeyAppBindings.length : 0;
      hotkeyAppBindings = (Array.isArray(hotkeyAppBindings) ? hotkeyAppBindings : [])
        .filter((entry) => String(entry?.hotkeyId || "").trim() !== normalizedId);
      if (hotkeyAppBindings.length === before) return false;
      saveHotkeyAppBindings();
      return true;
    }

    function collectPublishedHotkeyEntries() {
      function buildEntries(items, sourceType) {
        return (Array.isArray(items) ? items : [])
          .map((item) => {
            const shortcut = String(item?.hotkey || "").trim();
            const rawId = String(item?.id || "").trim();
            if (!shortcut || !rawId) return null;
            const id = `${sourceType}:${rawId}`;
            const binding = getHotkeyAppBindingById(id);
            if (!getAutomationEffectiveEnabled(sourceType, item)) return null;
            return {
              id,
              label: String(item?.name || "").trim() || id,
              sourceType,
              shortcut,
              launch: `kc-automation://${sourceType}:${rawId}`,
              gameBindingEnabled: Boolean(String(binding?.processName || "").trim()),
              gameMatchText: String(binding?.processName || "").trim()
            };
          })
          .filter(Boolean);
      }

      const appsFilesEntries = buildEntries(appsFilesAutomations, "apps-files");
      const keyboardEntries = buildEntries(keyboardAutomations, "keyboard");
      const mouseEntries = buildEntries(mouseAutomations, "mouse");
      const systemEntries = buildEntries(systemAutomations, "system");
      const profileEntries = buildEntries(profileAutomations, "profile");
      return [...appsFilesEntries, ...keyboardEntries, ...mouseEntries, ...systemEntries, ...profileEntries];
    }

    function publishAutomationHotkeys() {
      setExternalHotkeys(collectPublishedHotkeyEntries());
    }

    function deriveNameFromTarget(target, kind) {
      const raw = String(target || "").trim();
      if (!raw) return kind === "url" ? "Neue URL" : "Neue Aktion";
      if (kind === "url") {
        const noProto = raw.replace(/^https?:\/\//i, "").replace(/\/$/, "");
        return noProto || "Neue URL";
      }
      const normalized = raw.replace(/\\/g, "/").replace(/\/$/, "");
      const parts = normalized.split("/").filter(Boolean);
      return parts[parts.length - 1] || raw;
    }

    function deriveKeyboardName(step) {
      const kind = KEYBOARD_STEP_KINDS.includes(step?.kind) ? step.kind : "key";
      const value = String(step?.value || "").trim();
      if (!value) return "Neue Tastatur-Aktion";
      if (kind === "delay") return `Wait ${value} ms`;
      return value;
    }

    function cloneMouseSteps(steps) {
      return (Array.isArray(steps) ? steps : []).map((step) => ({
        id: String(step?.id || uid()),
        kind: MOUSE_STEP_KINDS.includes(step?.kind) ? step.kind : "click",
        value: String(step?.value || "")
      }));
    }

    function mouseButtonLabel(value, isDe) {
      const key = String(value || "").trim().toLowerCase();
      if (key === "right") return isDe ? "Rechtsklick" : "Right";
      if (key === "middle") return isDe ? "Mittlere Taste" : "Middle";
      if (key === "x1") return isDe ? "Seitentaste 1" : "Side button 1";
      if (key === "x2") return isDe ? "Seitentaste 2" : "Side button 2";
      return isDe ? "Linksklick" : "Left";
    }

    function deriveMouseName(step, isDe) {
      const kind = MOUSE_STEP_KINDS.includes(step?.kind) ? step.kind : "click";
      const value = String(step?.value || "").trim();
      if (!value) return isDe ? "Neue Maus-Aktion" : "New mouse action";
      if (kind === "delay") return `${isDe ? "Warte" : "Wait"} ${value} ms`;
      if (kind === "move") return `${isDe ? "Bewegen" : "Move"} ${value}`;
      if (kind === "scroll") return `${isDe ? "Scrollen" : "Scroll"} ${value}`;
      return `${mouseStepKindLabel(kind, isDe)} ${mouseButtonLabel(value, isDe)}`;
    }

    function cloneSystemSteps(steps) {
      return (Array.isArray(steps) ? steps : []).map((step) => ({
        id: String(step?.id || uid()),
        kind: SYSTEM_STEP_KINDS.includes(step?.kind) ? step.kind : "volume",
        value: String(step?.value || ""),
        amount: Math.max(1, Math.round(Number(step?.amount) || 1))
      }));
    }

    function cloneProfileSteps(steps) {
      return (Array.isArray(steps) ? steps : []).map((step) => ({
        id: String(step?.id || uid()),
        kind: PROFILE_STEP_KINDS.includes(step?.kind) ? step.kind : "apps-files",
        refId: String(step?.refId || ""),
        value: String(step?.value || "")
      }));
    }

    function deriveSystemName(step, isDe) {
      const kind = SYSTEM_STEP_KINDS.includes(step?.kind) ? step.kind : "volume";
      const value = String(step?.value || "").trim();
      if (!value) return isDe ? "Neue System-Aktion" : "New system action";
      if (kind === "delay") return `${isDe ? "Warte" : "Wait"} ${value} ms`;
      return systemActionLabel(value, isDe);
    }

    function deriveProfileName(step, isDe) {
      if (!step) return isDe ? "Neue Kombination" : "New combination";
      if (step.kind === "delay") return `${isDe ? "Warte" : "Wait"} ${step.value || "100"} ms`;
      const label = getProfileReferenceLabel(step.kind, step.refId, isDe);
      return label || (isDe ? "Neue Kombination" : "New combination");
    }

    function cloneKeyboardSteps(steps) {
      return (Array.isArray(steps) ? steps : []).map((step) => ({
        id: String(step?.id || uid()),
        kind: KEYBOARD_STEP_KINDS.includes(step?.kind) ? step.kind : "key",
        value: String(step?.value || "")
      }));
    }

    function getAutomationHotkeyConflict(hotkey, ignoreType = "", ignoreId = "") {
      const needle = normalizeShortcutCompareValue(hotkey);
      if (!needle) return null;
      const pools = [
        { type: "apps-files", items: appsFilesAutomations },
        { type: "keyboard", items: keyboardAutomations },
        { type: "mouse", items: mouseAutomations },
        { type: "system", items: systemAutomations },
        { type: "profile", items: profileAutomations }
      ];
      for (const pool of pools) {
        const match = (Array.isArray(pool.items) ? pool.items : []).find((item) => {
          if (pool.type === String(ignoreType || "") && String(item?.id || "") === String(ignoreId || "")) return false;
          return normalizeShortcutCompareValue(item?.hotkey) === needle;
        });
        if (match) return match;
      }
      return null;
    }

    function normalizeUrl(url) {
      const value = String(url || "").trim();
      if (!value) return "";
      if (/^[a-zA-Z][a-zA-Z0-9+.-]*:\/\//.test(value)) return value;
      if (/^[a-zA-Z][a-zA-Z0-9+.-]*:/.test(value)) return value;
      if (/^[\w.-]+\.[a-zA-Z]{2,}/.test(value)) return `https://${value}`;
      return value;
    }

    async function runSingleStep(step) {
      const kind = APPS_FILES_KINDS.includes(step?.kind) ? step.kind : "app";
      const target = String(step?.target || "").trim();
      if (!target) return;
      if (kind === "delay") {
        const ms = Number(target);
        if (Number.isFinite(ms) && ms >= 0) {
          await delay(ms);
        }
        return;
      }
      const launch = kind === "url" ? normalizeUrl(target) : target;
      try {
        const tauriApi = window.__TAURI__;
        if (tauriApi?.core?.invoke) {
          await tauriApi.core.invoke("open_external", { url: launch });
          return;
        }
      } catch (err) {
        console.error("runSingleStep failed:", err);
      }
      if (kind === "url") window.open(launch, "_blank", "noopener,noreferrer");
    }

    async function runAppsFilesAutomation(item, controller = null) {
      const steps = Array.isArray(item?.steps) ? item.steps : [];
      for (const step of steps) {
        if (controller?.active === false) return;
        if (step?.kind === "delay") {
          const ms = Number(step?.target);
          if (Number.isFinite(ms) && ms >= 0) {
            const finished = await delayInterruptible(ms, controller, 10);
            if (!finished) return;
          }
          continue;
        }
        await runSingleStep(step);
      }
    }

    async function runAppsFilesAutomationById(id) {
      const automationId = String(id || "").trim();
      if (!automationId) return;
      const item = appsFilesAutomations.find((entry) => entry.id === automationId);
      if (!item || !getAutomationEffectiveEnabled("apps-files", item) || !isAutomationRuntimeAllowed("apps-files", item)) return;
      await runAppsFilesAutomation(item);
    }

    function getAppsFilesHotkeyConflict(hotkey, ignoreId = "") {
      return getAutomationHotkeyConflict(hotkey, "apps-files", ignoreId);
    }

    function validateAppsFilesSteps(steps, isDe) {
      const cleaned = [];
      for (let i = 0; i < (Array.isArray(steps) ? steps.length : 0); i += 1) {
        const step = steps[i] || {};
        const kind = APPS_FILES_KINDS.includes(step.kind) ? step.kind : "app";
        const target = kind === "delay"
          ? normalizeDelayMs(step.target)
          : String(step.target || "").trim();
        if (!target) {
          return { error: isDe ? `Schritt ${i + 1} ist leer.` : `Step ${i + 1} is empty.`, steps: [] };
        }
        if (kind === "delay") {
          const ms = Number(target);
          if (!Number.isFinite(ms) || ms < 0) {
            return { error: isDe ? `Schritt ${i + 1} hat keinen g?ltigen Delay-Wert.` : `Step ${i + 1} has an invalid delay value.`, steps: [] };
          }
        }
        if (kind === "url") {
          const normalized = normalizeUrl(target);
          if (!/^[a-zA-Z][a-zA-Z0-9+.-]*:/.test(normalized)) {
            return { error: isDe ? `Schritt ${i + 1} hat keine g?ltige URL.` : `Step ${i + 1} does not have a valid URL.`, steps: [] };
          }
        }
        cleaned.push({
          id: String(step.id || uid()),
          kind,
          target,
          appName: String(step?.appName || "")
        });
      }
      if (!cleaned.length) {
        return { error: isDe ? "F?ge mindestens einen Schritt hinzu." : "Add at least one step.", steps: [] };
      }
      return { error: "", steps: cleaned };
    }

    async function runAppsFilesDraftTest(isDe) {
      const name = String(appsFilesDraft.name || "").trim();
      if (!name) {
        appsFilesFormError = isDe ? "Bitte gib einen Namen ein." : "Please enter a name.";
        render();
        return;
      }
      const validation = validateAppsFilesSteps(appsFilesDraft.steps, isDe);
      if (validation.error) {
        appsFilesFormError = validation.error;
        render();
        return;
      }
      appsFilesFormError = "";
      await runAppsFilesAutomation({ steps: validation.steps, enabled: true });
    }

    function keyboardStepKindLabel(kind, isDe) {
      if (kind === "combo") return isDe ? "Kombination" : "Combo";
      if (kind === "delay") return "Delay";
      return isDe ? "Taste" : "Key";
    }

    function keyboardStepKindCode(kind) {
      if (kind === "combo") return "COMBO";
      if (kind === "delay") return "WAIT";
      return "KEY";
    }

    function keyboardTargetPlaceholder(kind, isDe) {
      if (kind === "combo") return isDe ? "z. B. Ctrl+Shift+S" : "e.g. Ctrl+Shift+S";
      if (kind === "delay") return isDe ? "z. B. 100" : "e.g. 100";
      return isDe ? "z. B. Q oder Enter" : "e.g. Q or Enter";
    }

    function splitKeyboardValueParts(value) {
      return String(value || "")
        .split("+")
        .map((part) => part.trim())
        .filter(Boolean);
    }

    function formatKeyboardStepSummary(step) {
      const kind = KEYBOARD_STEP_KINDS.includes(step?.kind) ? step.kind : "key";
      const value = String(step?.value || "").trim();
      if (!value) return "";
      if (kind === "delay") return `${value} ms`;
      return value;
    }

    function getKeyboardFilterOptions(isDe) {
      return [
        { value: "all", label: isDe ? "Alle" : "All" },
        { value: "enabled", label: isDe ? "Aktiviert" : "Enabled" },
        { value: "disabled", label: isDe ? "Deaktiviert" : "Disabled" },
        { value: "key", label: isDe ? "Taste" : "Key" },
        { value: "combo", label: isDe ? "Kombination" : "Combo" },
        { value: "flow", label: "Flow" }
      ];
    }

    function getKeyboardPrimaryKind(item) {
      const steps = Array.isArray(item?.steps) ? item.steps : [];
      if (steps.length !== 1) return "flow";
      return KEYBOARD_STEP_KINDS.includes(steps[0]?.kind) ? steps[0].kind : "key";
    }

    function getKeyboardFilterValue(item) {
      if (keyboardListFilter === "enabled" || keyboardListFilter === "disabled") {
        return getAutomationEffectiveEnabled("keyboard", item) ? "enabled" : "disabled";
      }
      return getKeyboardPrimaryKind(item);
    }

    function keyboardTriggerModeLabel(mode, isDe) {
      if (mode === "hold") return isDe ? "Gedr\u00FCckt halten" : "While held";
      if (mode === "toggle") return isDe ? "Umschalten" : "Toggle";
      return isDe ? "Einmal" : "Once";
    }

    function keyboardTriggerModeIcon(mode) {
      if (mode === "hold") {
        return "&#x21BA;";
      }
      if (mode === "toggle") {
        return `
          <svg viewBox="0 0 24 24" focusable="false" aria-hidden="true">
            <rect x="3" y="7" width="18" height="10" rx="5" fill="none" stroke="currentColor" stroke-width="1.9"/>
            <circle cx="16" cy="12" r="3.2" fill="currentColor"/>
          </svg>
        `;
      }
      return `
        <svg viewBox="0 0 24 24" focusable="false" aria-hidden="true">
          <path d="M5 12H19" fill="none" stroke="currentColor" stroke-width="1.9" stroke-linecap="round"/>
          <path d="M13 6L19 12L13 18" fill="none" stroke="currentColor" stroke-width="1.9" stroke-linecap="round" stroke-linejoin="round"/>
        </svg>
      `;
    }

    function getKeyboardInfoLines(item, isDe) {
      return (Array.isArray(item?.steps) ? item.steps : []).map((step, idx) => {
        const label = keyboardStepKindLabel(step?.kind, isDe);
        return `${idx + 1}. ${label}: ${formatKeyboardStepSummary(step) || "-"}`;
      });
    }

    function validateKeyboardSteps(steps, isDe) {
      const cleaned = [];
      for (let i = 0; i < (Array.isArray(steps) ? steps.length : 0); i += 1) {
        const step = steps[i] || {};
        const kind = KEYBOARD_STEP_KINDS.includes(step.kind) ? step.kind : "key";
        const value = kind === "delay"
          ? normalizeDelayMs(step.value)
          : String(step.value || "").trim();
        if (!value) {
          return { error: isDe ? `Schritt ${i + 1} ist leer.` : `Step ${i + 1} is empty.`, steps: [] };
        }
        if (kind === "delay") {
          const ms = Number(value);
          if (!Number.isFinite(ms) || ms < 0) {
      return { error: isDe ? `Schritt ${i + 1} hat keinen gueltigen Delay-Wert.` : `Step ${i + 1} has an invalid delay value.`, steps: [] };
          }
        } else if (kind === "key") {
          const parts = splitKeyboardValueParts(value);
          if (parts.length !== 1) {
            return {
              error: isDe
                ? `Schritt ${i + 1} muss genau eine Taste enthalten.`
                : `Step ${i + 1} must contain exactly one key.`,
              steps: []
            };
          }
        } else if (kind === "combo") {
          const parts = splitKeyboardValueParts(value);
          if (parts.length < 2) {
            return {
              error: isDe
        ? `Schritt ${i + 1} braucht mindestens zwei Tasten fuer eine Kombination.`
                : `Step ${i + 1} needs at least two keys for a combination.`,
              steps: []
            };
          }
        }
        cleaned.push({
          id: String(step.id || uid()),
          kind,
          value
        });
      }
      if (!cleaned.length) {
  return { error: isDe ? "Fuege mindestens einen Schritt hinzu." : "Add at least one step.", steps: [] };
      }
      return { error: "", steps: cleaned };
    }

    async function runKeyboardAutomation(item, controller = null) {
      const steps = Array.isArray(item?.steps) ? item.steps : [];
      const tauriApi = window.__TAURI__;
      if (!tauriApi?.core?.invoke) {
        throw new Error("Keyboard automation requires the desktop app.");
      }
      for (const step of steps) {
        if (controller?.active === false) return;
        const kind = KEYBOARD_STEP_KINDS.includes(step?.kind) ? step.kind : "key";
        const value = String(step?.value || "").trim();
        if (!value) continue;
        if (kind === "delay") {
          const ms = Number(value);
          if (!Number.isFinite(ms) || ms < 0) continue;
          const finished = await delayInterruptible(ms, controller, 10);
          if (!finished) return;
          continue;
        }
        await tauriApi.core.invoke("run_keyboard_sequence", {
          steps: [{ kind, value }]
        });
      }
    }

    function stopKeyboardLoop(id) {
      const key = String(id || "");
      const controller = keyboardLoopControllers.get(key);
      if (!controller) return;
      controller.active = false;
      keyboardLoopControllers.delete(key);
    }

    async function startKeyboardLoop(item) {
      const automationId = String(item?.id || "").trim();
      if (!automationId || keyboardLoopControllers.has(automationId)) return;
      const controller = { active: true };
      keyboardLoopControllers.set(automationId, controller);
      while (controller.active) {
        try {
          await runKeyboardAutomation(item, controller);
        } catch (err) {
          console.error("keyboard loop failed:", err);
          controller.active = false;
          break;
        }
        if (!controller.active) break;
      }
      if (keyboardLoopControllers.get(automationId) === controller) {
        keyboardLoopControllers.delete(automationId);
      }
    }

    async function handleKeyboardAutomationTrigger(item, phase) {
      const mode = ["once", "hold", "toggle"].includes(String(item?.triggerMode || "").trim())
        ? String(item.triggerMode).trim()
        : "once";
      const automationId = String(item?.id || "").trim();
      if (!automationId) return;
      if (mode === "hold") {
        if (phase === "pressed") {
          await startKeyboardLoop(item);
        } else if (phase === "released") {
          stopKeyboardLoop(automationId);
        }
        return;
      }
      if (mode === "toggle") {
        if (phase !== "pressed") return;
        if (keyboardLoopControllers.has(automationId)) {
          stopKeyboardLoop(automationId);
        } else {
          await startKeyboardLoop(item);
        }
        return;
      }
      if (phase === "pressed") {
        if (keyboardRunningOnce.has(automationId)) return;
        keyboardRunningOnce.add(automationId);
        try {
          await runKeyboardAutomation(item);
        } finally {
          keyboardRunningOnce.delete(automationId);
        }
      }
    }

    async function runKeyboardAutomationById(id, phase = "pressed") {
      const automationId = String(id || "").trim();
      if (!automationId) return;
      const item = keyboardAutomations.find((entry) => entry.id === automationId);
      if (!item || !getAutomationEffectiveEnabled("keyboard", item) || !isAutomationRuntimeAllowed("keyboard", item)) return;
      await handleKeyboardAutomationTrigger(item, String(phase || "pressed"));
    }

    async function runKeyboardDraftTest(isDe) {
      const name = String(keyboardDraft.name || "").trim();
      if (!name) {
        keyboardFormError = isDe ? "Bitte gib einen Namen ein." : "Please enter a name.";
        render();
        return;
      }
      const validation = validateKeyboardSteps(keyboardDraft.steps, isDe);
      if (validation.error) {
        keyboardFormError = validation.error;
        render();
        return;
      }
      keyboardFormError = "";
      await runKeyboardAutomation({ steps: validation.steps, enabled: true });
    }

    function mouseStepKindLabel(kind, isDe) {
      if (kind === "down") return isDe ? "Dr\u00FCcken" : "Press";
      if (kind === "up") return isDe ? "Loslassen" : "Release";
      if (kind === "move") return isDe ? "Bewegen" : "Move";
      if (kind === "scroll") return isDe ? "Scrollen" : "Scroll";
      if (kind === "delay") return "Delay";
      return isDe ? "Klick" : "Click";
    }

    function mouseStepKindCode(kind) {
      if (kind === "down") return "DOWN";
      if (kind === "up") return "UP";
      if (kind === "move") return "MOVE";
      if (kind === "scroll") return "SCROLL";
      if (kind === "delay") return "WAIT";
      return "CLICK";
    }

    function mouseTargetPlaceholder(kind, isDe) {
      if (kind === "move") return isDe ? "z. B. 120,-40" : "e.g. 120,-40";
      if (kind === "scroll") return isDe ? "z. B. 120 oder -240" : "e.g. 120 or -240";
      if (kind === "delay") return isDe ? "z. B. 100" : "e.g. 100";
      return "";
    }

    function getMouseButtonOptions(isDe) {
      return MOUSE_BUTTON_VALUES.map((value) => ({
        value,
        label: mouseButtonLabel(value, isDe)
      }));
    }

    function parseMouseMoveValue(value) {
      const raw = String(value || "").trim();
      if (!raw) return null;
      const parts = raw.split(",").map((part) => part.trim()).filter(Boolean);
      if (parts.length !== 2 && parts.length !== 3) return null;
      const x = Number(parts[0]);
      const y = Number(parts[1]);
      const duration = parts.length >= 3 ? Number(parts[2]) : 220;
      if (!Number.isFinite(x) || !Number.isFinite(y) || !Number.isFinite(duration) || duration < 0) return null;
      return {
        x: Math.round(x),
        y: Math.round(y),
        duration: Math.round(duration),
        normalized: `${Math.round(x)},${Math.round(y)},${Math.round(duration)}`
      };
    }

    function formatMouseStepSummary(step, isDe) {
      const kind = MOUSE_STEP_KINDS.includes(step?.kind) ? step.kind : "click";
      const value = String(step?.value || "").trim();
      if (!value) return "";
      if (kind === "delay") return `${value} ms`;
      if (kind === "move") {
        const move = parseMouseMoveValue(value);
        if (!move) return `${isDe ? "Bewegen" : "Move"} ${value}`;
        return `${isDe ? "Delta" : "Delta"} ${move.x},${move.y} -> ${move.duration} ms`;
      }
      if (kind === "scroll") {
        const scroll = parseMouseScrollValue(value);
        if (!scroll) return `${isDe ? "Scrollen" : "Scroll"} ${value}`;
        return `${scroll.amount} -> ${scroll.duration} ms`;
      }
      return mouseButtonLabel(value, isDe);
    }

    function parseMouseScrollValue(value) {
      const raw = String(value || "").trim();
      if (!raw) return null;
      const parts = raw.split(",").map((part) => part.trim()).filter(Boolean);
      if (parts.length !== 1 && parts.length !== 2) return null;
      const amount = Number(parts[0]);
      const duration = parts.length >= 2 ? Number(parts[1]) : 180;
      if (!Number.isFinite(amount) || !Number.isFinite(duration) || duration < 0) return null;
      return {
        amount: Math.round(amount),
        duration: Math.round(duration),
        normalized: `${Math.round(amount)},${Math.round(duration)}`
      };
    }

