    (function bindAutomationHotkeyRunEvent() {
      try {
        const tauriApi = window.__TAURI__;
        if (!tauriApi?.event?.listen) return;
        tauriApi.event.listen("kc://run-automation", async (evt) => {
          const payload = evt?.payload;
          const payloadId = typeof payload === "string"
            ? payload
            : String(payload?.id || "");
          const phase = typeof payload === "object" && payload
            ? String(payload.phase || "pressed")
            : "pressed";
          if (!payloadId) return;
          if (payloadId.startsWith("apps-files:")) {
            if (phase === "pressed") {
              await runAppsFilesAutomationById(payloadId.slice("apps-files:".length));
            }
            return;
          }
          if (payloadId.startsWith("keyboard:")) {
            await runKeyboardAutomationById(payloadId.slice("keyboard:".length), phase);
            return;
          }
          if (payloadId.startsWith("mouse:")) {
            await runMouseAutomationById(payloadId.slice("mouse:".length), phase);
            return;
          }
          if (payloadId.startsWith("system:")) {
            await runSystemAutomationById(payloadId.slice("system:".length), phase);
            return;
          }
          if (payloadId.startsWith("profile:")) {
            await runProfileAutomationById(payloadId.slice("profile:".length), phase);
            return;
          }
          if (phase === "pressed") {
            await runAppsFilesAutomationById(payloadId);
          }
        });
      } catch (err) {
        console.error("bindAutomationHotkeyRunEvent failed:", err);
      }
    })();

