          if (e.key === "Backspace" || e.key === "Delete") { profileDraft.hotkey = ""; if (input) input.value = ""; profileCapturingHotkey = false; document.removeEventListener("keydown", onProfileHotkeyCaptureKeydown, true); document.removeEventListener("mousedown", onProfileHotkeyCaptureMousedown, true); if (btn) btn.textContent = isDe ? "Aufnehmen" : "Capture"; publishAutomationHotkeys(); return; }
